// The mutation executed by PromoteIdeaToEpic.
const PromoteIdeaToEpic_Operation = `
mutation PromoteIdeaToEpic ($ideaId: ID!, $releaseId: ID) {
	promoteIdea(id: $ideaId, type: Epic, releaseId: $releaseId) {
		idea {
			id
			referenceNum
			name
		}
		promotable {
			__typename
			... on Epic {
				id
				referenceNum
				name
			}
		}
		errors {
			attributes {
				name
				fullMessages
			}
		}
	}
}
`

